sp_rectangle_menu_item.record_script:
// Menu Item Label
var label = 'Awaiting Extension Approval';

// maximum number of entries in this Menu
var max = 5;

var t = data;  // shortcut
t.items = [];

var u = gs.getUser().getID();


// use record watchers to tell header when to update dropdown counts
var filter = 'active=true^state=13^extension_requested=true^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe';

t.record_watchers = [];
t.record_watchers.push({'table':'x_153465_discovert_route_task_instance','filter': filter});

var z = new GlideRecord('x_153465_discovert_route_task_instance');
z.addActiveQuery();
z.addQuery('extension_requested', 'true');
z.addEncodedQuery(filter);
z.orderByDesc('sys_updated_on');
z.setLimit(max);
z.query();

var a = new GlideAggregate('x_153465_discovert_route_task_instance');
a.addEncodedQuery(filter);
a.addAggregate("COUNT");
a.query();


var totcount = 0;
if(a.next()){
   totcount = a.getAggregate("COUNT");
}

while (z.next()) {
 t.items.push({
    title: z.getValue('task_name') ,
    type: 'link',
    href: '?sys_id='+ z.getValue('sys_id') + '&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance'
  }); 

 if (!z.canRead())
    continue;

  var a = {};
  //$sp.getRecordValues(a, z, 'short_description,sys_id,number,sys_updated_on');
  if (z.short_description.nil())
    a.short_description = "(No description)";
  a.__table = z.getTableName();
  a.type = 'record';
  //a.sortOrder = z.sys_updated_on.getGlideObject().getNumericValue();
  //t.items.push(a);

}
t.items.sort(function(a, b) {
  return b.sortOrder - a.sortOrder;
});
//t.items = t.items.slice(0, max); // only want first 30
t.items = t.items.slice(0, max); 
//t.count = t.items.length;
t.count = totcount;

//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter=reassignment_requested%3Dtrue%5EORstateIN-5%5Esys_created_by%3Djavascript:gs.getUserName();', items: []};
//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=active%3Dtrue%5Eextension_requested%3Dtrue%5EoriginatorDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5EEQ', items: []};
//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=active%3Dtrue%5Eextension_requested%3Dtrue%5Eparent.assigned_toDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5ENQparent.numberISEMPTY%5EoriginatorDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5Eactive%3Dtrue%5Eextension_requested%3Dtrue%5EEQ', items: []};
//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=u_reviewer='+u+'^state=13^extension_requested=true^active=true', items: []};
//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=parent.assigned_to='+u+'^state=13^extension_requested=true^active=true^NQparent.numberISEMPTY^originator='+u+'^state=13^extension_requested=true^active=true'+ '&label='+label, items: []};

//var uri = '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=active=true^state=13^extension_requested=true^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe'
//var url = '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=u_task_requester='+u+'^state=13^extension_requested=true^active=true'+ '&label='+label, 

var link = {
              title: gs.getMessage('View all requests'), 
              type: 'link', 
              href: '?id=discovertasker_detailsdrilldown&view=Extensions&table=x_153465_discovert_route_task_instance&filter=u_task_requester='+u+'^state=13^extension_requested=true^active=true'+ '&label='+label, 
              items: []
              };
t.items.push(link); // put 'View all requests' first
